import io
import xml.etree.ElementTree as ET

from ..utils import _add_created_with_comment, _add_path_text, _ensure_path


def _add_path_attr(root: ET.Element, tags: list[str], attr_name: str, value) -> None:
    if value is None:
        return
    target = _ensure_path(root, tags)
    if attr_name not in target.attrib:
        target.set(attr_name, str(value))

def construct_nportp(rows: list) -> bytes:
    normalized_rows = []
    if rows:
        for row in rows:
            if isinstance(row, dict) or hasattr(row, "get"):
                normalized_rows.append(row)
            else:
                normalized_rows.append(dict(row))
    else:
        normalized_rows = [{}]

    root = ET.Element('edgarSubmission')
    root.set('xmlns', 'http://www.sec.gov/edgar/nport')
    root.set('xmlns:com', 'http://www.sec.gov/edgar/common')
    root.set('xmlns:ncom', 'http://www.sec.gov/edgar/nportcommon')
    root.set('xmlns:xsi', 'http://www.w3.org/2001/XMLSchema-instance')
    for row in normalized_rows:
        _add_path_text(root, ['documents'], row.get('documents'))
